package com.clashcoach.recommendation;
import com.clashcoach.player.*; import com.fasterxml.jackson.core.JsonProcessingException; import com.fasterxml.jackson.databind.*; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class RecommendationService { private static final String RULE="hero-lowest-level-v1"; private final RecommendationRepository repository; private final ObjectMapper mapper; public RecommendationService(RecommendationRepository repository,ObjectMapper mapper){this.repository=repository;this.mapper=mapper;} @Transactional public Recommendation create(PlayerSnapshot snapshot){ try { List<PlayerData.Hero> heroes=Arrays.asList(mapper.readValue(snapshot.getHeroesJson(),PlayerData.Hero[].class)); Optional<PlayerData.Hero> hero=heroes.stream().min(Comparator.comparingInt(PlayerData.Hero::getLevel).thenComparing(PlayerData.Hero::getName)); Recommendation result=hero.<Recommendation>map(item->new Recommendation(snapshot,"UPGRADE_HERO","HIGH","[\"LOWEST_LEVEL_HERO\"]","Prioritize upgrading "+item.getName()+" (level "+item.getLevel()+"), your lowest-level hero.",RULE)).orElseGet(()->new Recommendation(snapshot,"INSUFFICIENT_DATA","INFO","[\"HERO_DATA_UNAVAILABLE\"]","Hero data is unavailable, so a reliable upgrade priority cannot be calculated.",RULE)); return repository.save(result); } catch(JsonProcessingException exception){ throw new IllegalStateException("Stored hero data is invalid",exception); } } public Optional<Recommendation> find(PlayerSnapshot snapshot){return repository.findFirstBySnapshotOrderByCreatedAtDesc(snapshot);} }
